import 'package:flutter/material.dart';
import 'package:task_manager_flutter/data/models/venda_model.dart';
import 'package:task_manager_flutter/data/services/vendas_caller.dart';

// Define cores
const Color lightGreenBackground = Color.fromARGB(255, 231, 247, 233);
const Color mediumGreenBackground = Color.fromARGB(255, 200, 230, 200);
const Color darkGreenBorder = Color.fromARGB(255, 1, 247, 14);

class ContratosMovimento extends StatefulWidget {
  const ContratosMovimento({Key? key}) : super(key: key);

  @override
  _ContratosMovimentoState createState() => _ContratosMovimentoState();
}

class _ContratosMovimentoState extends State<ContratosMovimento> {
  List<Produto> allProducts = [];
  List<dynamic> filteredProducts = [];
  bool isLoading = true;

  String selectedState = "Estado";
  String selectedCity = "Cidade";

  @override
  void initState() {
    super.initState();
    _fetchProducts();
  }

  Future<void> _fetchProducts() async {
    setState(() {
      isLoading = true;
    });
    try {
      final data = await VendasCaller().fetchCotacoes(context);
      setState(() {
        allProducts = data;
        filteredProducts = data;
      });
    } catch (e) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(content: Text('Erro ao carregar produtos: $e')),
      );
    } finally {
      setState(() {
        isLoading = false;
      });
    }
  }

  void applyFilters() {
    setState(() {
      filteredProducts = allProducts.where((product) {
        final stateMatch = selectedState == "Estado" ||
            (product.parceiro?.endereco?.estado?.toString() ?? '') ==
                selectedState;
        final cityMatch = selectedCity == "Cidade" ||
            (product.parceiro?.endereco?.cidade?.toString() ?? '') ==
                selectedCity;

        return stateMatch && cityMatch;
      }).toList();
    });
  }

  void _showDownloadAndUploadButtons(String status) {
    showDialog(
      context: context,
      builder: (context) {
        return AlertDialog(
          backgroundColor: lightGreenBackground,
          title: Text('Contrato',
              style: TextStyle(
                  fontWeight: FontWeight.bold,
                  color: darkGreenBorder)),
          content: Column(
            mainAxisSize: MainAxisSize.min,
            children: [
              if (status == 'download' || status == 'both')
                SizedBox(
                  width: double.infinity,
                  child: ElevatedButton.icon(
                    icon: const Icon(Icons.download, size: 24),
                    label: const Text('Baixar Contrato Modelo',
                        style: TextStyle(fontSize: 16)),
                    style: ElevatedButton.styleFrom(
                      backgroundColor: darkGreenBorder,
                      foregroundColor: Colors.white,
                      padding: const EdgeInsets.symmetric(vertical: 15),
                      shape: RoundedRectangleBorder(
                        borderRadius: BorderRadius.circular(10),
                        side: BorderSide(color: darkGreenBorder),
                      ),
                    ),
                    onPressed: () => _downloadContract(widget.idVenda, context),
                  ),
                ),
              if (status == 'upload' || status == 'both')
                SizedBox(height: 15),
              if (status == 'upload' || status == 'both')
                SizedBox(
                  width: double.infinity,
                  child: ElevatedButton.icon(
                    icon: const Icon(Icons.upload, size: 24),
                    label: const Text('Enviar Contrato Assinado',
                        style: TextStyle(fontSize: 16)),
                    style: ElevatedButton.styleFrom(
                      backgroundColor: darkGreenBorder,
                      foregroundColor: Colors.white,
                      padding: const EdgeInsets.symmetric(vertical: 15),
                      shape: RoundedRectangleBorder(
                        borderRadius: BorderRadius.circular(10),
                        side: BorderSide(color: darkGreenBorder),
                      ),
                    ),
                    onPressed: () => _uploadContract(widget.idVenda),
                  ),
                ),
            ],
          ),
          actions: [
            TextButton(
              onPressed: () => Navigator.pop(context),
              child: Text('Fechar',
                  style: TextStyle(
                      fontWeight: FontWeight.bold,
                      color: darkGreenBorder)),
            ),
          ],
          shape: RoundedRectangleBorder(
            borderRadius: BorderRadius.circular(15),
            side: BorderSide(color: darkGreenBorder, width: 2),
          ),
        );
      },
    );
  }
}
